# --- CoAP Constants ---
COAP_VERSION = 1
COAP_PORT = 5684  # DTLS-secured CoAP port (not 5683 which is insecure)

# CoAP Message Types
CON = 0  # Confirmable
NON = 1  # Non-confirmable
ACK = 2  # Acknowledgement
RST = 3  # Reset

# CoAP Method Codes
EMPTY = 0
GET = 1
POST = 2
PUT = 3
DELETE = 4

# CoAP Response Codes (class.detail encoded as (class * 32) + detail)
RESPONSE_CONTENT = (2 << 5) | 5        # 2.05 Content
RESPONSE_CHANGED = (2 << 5) | 4        # 2.04 Changed
RESPONSE_BAD_REQUEST = (4 << 5) | 0    # 4.00 Bad Request
RESPONSE_NOT_FOUND = (4 << 5) | 4      # 4.04 Not Found
RESPONSE_METHOD_NOT_ALLOWED = (4 << 5) | 5  # 4.05 Method Not Allowed
RESPONSE_UNAUTHORIZED = (4 << 5) | 1   # 4.01 Unauthorized
RESPONSE_INTERNAL_ERROR = (5 << 5) | 0 # 5.00 Internal Server Error

# CoAP Option Numbers
OPTION_URI_PATH = 11
OPTION_CONTENT_FORMAT = 12
OPTION_URI_QUERY = 15

# Content Formats
CONTENT_PLAIN_TEXT = 0
CONTENT_JSON = 50


class CoapMessage:
    """Minimal CoAP message parser and builder."""

    def __init__(self):
        self.version = COAP_VERSION
        self.msg_type = CON
        self.code = EMPTY
        self.message_id = 0
        self.token = b""
        self.options = []
        self.payload = b""

    @staticmethod
    def parse(data):
        """Parse raw bytes into a CoapMessage."""
        if len(data) < 4:
            return None

        msg = CoapMessage()
        first_byte = data[0]
        msg.version = (first_byte >> 6) & 0x03
        msg.msg_type = (first_byte >> 4) & 0x03
        token_length = first_byte & 0x0F
        msg.code = data[1]
        msg.message_id = (data[2] << 8) | data[3]

        if msg.version != COAP_VERSION:
            return None

        if token_length > 8:
            return None

        offset = 4
        if token_length > 0:
            if offset + token_length > len(data):
                return None
            msg.token = data[offset:offset + token_length]
            offset += token_length

        # Parse options
        prev_option_number = 0
        while offset < len(data):
            if data[offset] == 0xFF:
                offset += 1
                msg.payload = data[offset:]
                break

            option_delta = (data[offset] >> 4) & 0x0F
            option_length = data[offset] & 0x0F
            offset += 1

            if option_delta == 13:
                if offset >= len(data):
                    return None
                option_delta = data[offset] + 13
                offset += 1
            elif option_delta == 14:
                if offset + 1 >= len(data):
                    return None
                option_delta = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            if option_length == 13:
                if offset >= len(data):
                    return None
                option_length = data[offset] + 13
                offset += 1
            elif option_length == 14:
                if offset + 1 >= len(data):
                    return None
                option_length = ((data[offset] << 8) | data[offset + 1]) + 269
                offset += 2

            option_number = prev_option_number + option_delta
            if offset + option_length > len(data):
                return None
            option_value = data[offset:offset + option_length]
            offset += option_length

            msg.options.append((option_number, option_value))
            prev_option_number = option_number

        return msg

    def get_uri_path(self):
        """Extract URI path from options."""
        parts = []
        for opt_num, opt_val in self.options:
            if opt_num == OPTION_URI_PATH:
                try:
                    parts.append(opt_val.decode("utf-8"))
                except (UnicodeDecodeError, AttributeError):
                    parts.append(str(opt_val))
        return "/" + "/".join(parts) if parts else "/"

    def to_bytes(self):
        """Serialize message to bytes."""
        token_length = len(self.token)
        first_byte = ((self.version & 0x03) << 6) | \
                     ((self.msg_type & 0x03) << 4) | \
                     (token_length & 0x0F)

        buf = bytearray()
        buf.append(first_byte)
        buf.append(self.code & 0xFF)
        buf.append((self.message_id >> 8) & 0xFF)
        buf.append(self.message_id & 0xFF)

        if self.token:
            buf.extend(self.token)

        # Sort options by number for proper delta encoding
        sorted_options = sorted(self.options, key=lambda x: x[0])
        prev_option_number = 0

        for opt_num, opt_val in sorted_options:
            delta = opt_num - prev_option_number
            length = len(opt_val)

            # Encode delta
            if delta < 13:
                delta_nibble = delta
                delta_ext = b""
            elif delta < 269:
                delta_nibble = 13
                delta_ext = bytes([delta - 13])
            else:
                delta_nibble = 14
                d = delta - 269
                delta_ext = bytes([(d >> 8) & 0xFF, d & 0xFF])

            # Encode length
            if length < 13:
                length_nibble = length
                length_ext = b""
            elif length < 269:
                length_nibble = 13
                length_ext = bytes([length - 13])
            else:
                length_nibble = 14
                le = length - 269
                length_ext = bytes([(le >> 8) & 0xFF, le & 0xFF])

            buf.append((delta_nibble << 4) | length_nibble)
            buf.extend(delta_ext)
            buf.extend(length_ext)
            buf.extend(opt_val)

            prev_option_number = opt_num

        if self.payload:
            buf.append(0xFF)
            buf.extend(self.payload)

        return bytes(buf)


class DeviceState:
    """Holds the current state of device sensors and actuators."""

    def __init__(self):
        self.light_state = False
        self.light_brightness = 0
        self._temp_offset = random.uniform(-2.0, 2.0)

    def read_temperature(self):
        """Read temperature sensor. Replace with actual hardware read."""
        # Simulate temperature reading; replace with real ADC/I2C read
        base_temp = 22.0 + self._temp_offset
        noise = random.uniform(-0.5, 0.5)
        return round(base_temp + noise, 2)

    def get_light_state(self):
        """Get current light actuator state."""
        return {
            "on": self.light_state,
            "brightness": self.light_brightness
        }

    def set_light_state(self, payload_str):
        """
        Set light actuator state from payload.
        Expected JSON: {"on": true/false, "brightness": 0-100}
        Returns True on success, error string on failure.
        """
        try:
            # Minimal JSON parsing for constrained devices
            data = self._parse_simple_json(payload_str)

            if "on" in data:
                val = data["on"]
                if val in ("true", "1", True):
                    self.light_state = True
                elif val in ("false", "0", False):
                    self.light_state = False
                else:
                    return "Invalid 'on' value"

            if "brightness" in data:
                brightness = int(data["brightness"])
                if 0 <= brightness <= 100:
                    self.light_brightness = brightness
                else:
                    return "Brightness must be 0-100"

            # In real hardware, drive GPIO/PWM here
            # e.g., pin.value(self.light_state)
            # e.g., pwm.duty(int(self.light_brightness * 10.23))

            return True
        except (ValueError, KeyError, TypeError) as e:
            return "Parse error: {}".format(str(e))

    @staticmethod
    def _parse_simple_json(s):
        """
        Ultra-minimal JSON-like parser for constrained devices.
        Handles flat key-value objects only.
        """
        s = s.strip()
        if s.startswith("{") and s.endswith("}"):
            s = s[1:-1].strip()

        result = {}
        pairs = s.split(",")
        for pair in pairs:
            if ":" not in pair:
                continue
            key, value = pair.split(":", 1)
            key = key.strip().strip('"').strip("'")
            value = value.strip().strip('"').strip("'")

            # Type coercion
            if value.lower() == "true":
                value = True
            elif value.lower() == "false":
                value = False
            else:
                try:
                    value = int(value)
                except ValueError:
                    try:
                        value = float(value)
                    except ValueError:
                        pass

            result[key] = value
        return result


class CoapResource:
    """Represents a single CoAP resource with allowed methods."""

    def __init__(self, path, get_handler=None, put_handler=None):
        self.path = path
        self.get_handler = get_handler
        self.put_handler = put_handler

    def handle(self, request):
        """Dispatch request to appropriate handler."""
        method = request.code

        if method == GET and self.get_handler:
            return self.get_handler(request)
        elif method == PUT and self.put_handler:
            return self.put_handler(request)
        else:
            return RESPONSE_METHOD_NOT_ALLOWED, b"Method not allowed", CONTENT_PLAIN_TEXT


class SecureCoapServer:
    """
    DTLS-secured CoAP server for MicroPython IoT devices.

    Security measures:
    - Uses DTLS (port 5684) instead of plain CoAP (port 5683)
    - Pre-shared key authentication
    - Input validation and size limits
    - Rate limiting per client
    """

    MAX_PAYLOAD_SIZE = 1024
    MAX_CLIENTS_TRACKED = 32
    RATE_LIMIT_WINDOW = 10  # seconds
    RATE_LIMIT_MAX_REQUESTS = 50  # max requests per window per client

    def __init__(self, host="0.0.0.0", port=COAP_PORT,
                 certfile=None, keyfile=None, psk=None, psk_identity=None):
        self.host = host
        self.port = port
        self.certfile = certfile
        self.keyfile = keyfile
        self.psk = psk
        self.psk_identity = psk_identity
        self.resources = {}
        self.device = DeviceState()
        self._rate_limit_table = {}
        self._running = False

        # Register default resources
        self._register_default_resources()

    def _register_default_resources(self):
        """Register built-in device resources."""

        # Temperature sensor resource (read-only)
        self.add_resource(
            "/sensors/temp",
            get_handler=self._handle_temp_get
        )

        # Light actuator resource (read/write)
        self.add_resource(
            "/actuators/light",
            get_handler=self._handle_light_get,
            put_handler=self._handle_light_put
        )

    def add_resource(self, path, get_handler=None, put_handler=None):
        """Register a CoAP resource."""
        self.resources[path] = CoapResource(path, get_handler, put_handler)

    def _handle_temp_get(self, request):
        """Handle GET /sensors/temp"""
        temp = self.device.read_temperature()
        payload = '{{"temperature": {}, "unit": "celsius"}}'.format(temp)
        return RESPONSE_CONTENT, payload.encode("utf-8"), CONTENT_JSON

    def _handle_light_get(self, request):
        """Handle GET /actuators/light"""
        state = self.device.get_light_state()
        on_str = "true" if state["on"] else "false"
        payload = '{{"on": {}, "brightness": {}}}'.format(
            on_str, state["brightness"]
        )
        return RESPONSE_CONTENT, payload.encode("utf-8"), CONTENT_JSON

    def _handle_light_put(self, request):
        """Handle PUT /actuators/light"""
        if not request.payload:
            return RESPONSE_BAD_REQUEST, b"Empty payload", CONTENT_PLAIN_TEXT

        try:
            payload_str = request.payload.decode("utf-8")
        except UnicodeDecodeError:
            return RESPONSE_BAD_REQUEST, b"Invalid encoding", CONTENT_PLAIN_TEXT

        # Validate payload size
        if len(payload_str) > self.MAX_PAYLOAD_SIZE:
            return RESPONSE_BAD_REQUEST, b"Payload too large", CONTENT_PLAIN_TEXT

        result = self.device.set_light_state(payload_str)

        if result is True:
            state = self.device.get_light_state()
            on_str = "true" if state["on"] else "false"
            resp = '{{"on": {}, "brightness": {}}}'.format(
                on_str, state["brightness"]
            )
            return RESPONSE_CHANGED, resp.encode("utf-8"), CONTENT_JSON
        else:
            return RESPONSE_BAD_REQUEST, str(result).encode("utf-8"), CONTENT_PLAIN_TEXT

    def _check_rate_limit(self, client_addr):
        """Simple rate limiting per client address."""
        now = time.time()
        addr_key = str(client_addr)

        # Clean old entries if table is too large
        if len(self._rate_limit_table) > self.MAX_CLIENTS_TRACKED:
            expired = [
                k for k, v in self._rate_limit_table.items()
                if now - v["window_start"] > self.RATE_LIMIT_WINDOW
            ]
            for k in expired:
                del self._rate_limit_table[k]

        if addr_key not in self._rate_limit_table:
            self._rate_limit_table[addr_key] = {
                "window_start": now,
                "count": 1
            }
            return True

        entry = self._rate_limit_table[addr_key]

        if now - entry["window_start"] > self.RATE_LIMIT_WINDOW:
            entry["window_start"] = now
            entry["count"] = 1
            return True

        entry["count"] += 1
        return entry["count"] <= self.RATE_LIMIT_MAX_REQUESTS

    def _build_response(self, request, code, payload, content_format):
        """Build a CoAP response message."""
        resp = CoapMessage()
        resp.version = COAP_VERSION

        if request.msg_type == CON:
            resp.msg_type = ACK
        else:
            resp.msg_type = NON

        resp.code = code
        resp.message_id = request.message_id
        resp.token = request.token

        # Add content-format option
        if content_format is not None:
            fmt_bytes = bytes([content_format])
            resp.options.append((OPTION_CONTENT_FORMAT, fmt_bytes))

        resp.payload = payload if isinstance(payload, bytes) else payload.encode("utf-8")
        return resp

    def _handle_request(self, data, client_addr):
        """Process an incoming CoAP request and return response bytes."""

        # Rate limiting
        if not self._check_rate_limit(client_addr):
            # Silently drop or send RST
            print("[SECURITY] Rate limit exceeded for {}".format(client_addr))
            return None

        # Size check
        if len(data) > 1500:
            print("[SECURITY] Oversized packet from {}".format(client_addr))
            return None

        # Parse message
        request = CoapMessage.parse(data)
        if request is None:
            print("[WARN] Malformed CoAP message from {}".format(client_addr))
            return None

        uri_path = request.get_uri_path()
        print("[INFO] {} {} from {}".format(
            {GET: "GET", PUT: "PUT", POST: "POST", DELETE: "DELETE"}.get(
                request.code, "UNKNOWN"
            ),
            uri_path,
            client_addr
        ))

        # Route to resource
        if uri_path in self.resources:
            resource = self.resources[uri_path]
            code, payload, content_format = resource.handle(request)
        else:
            code = RESPONSE_NOT_FOUND
            payload = b"Resource not found"
            content_format = CONTENT_PLAIN_TEXT

        response = self._build_response(request, code, payload, content_format)
        return response.to_bytes()

    def _create_ssl_context(self):
        """Create SSL context for DTLS. Adapt based on MicroPython SSL support."""
        try:
            # MicroPython's ssl module varies by port
            # For ESP32/ESP8266, use the available ssl wrapper
            ctx = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)

            if self.certfile and self.keyfile:
                ctx.load_cert_chain(self.certfile, self.keyfile)
                print("[SECURITY] Loaded TLS certificate and key")
            else:
                print("[WARN] No certificate provided; generating self-signed is not "
                      "recommended for production")

            # Enforce TLS 1.2+ if available
            try:
                ctx.minimum_version = ssl.TLSVersion.TLSv1_2
            except AttributeError:
                pass  # Not all MicroPython ports support this

            return ctx
        except Exception as e:
            print("[WARN] SSL context creation failed: {}".format(e))
            print("[WARN] Falling back to PSK-based authentication over UDP")
            return None

    def _validate_psk(self, data):
        """
        Simple PSK validation for environments without full DTLS.
        Expects first 32 bytes to be HMAC-like PSK token.
        Returns (is_valid, coap_data).
        """
        if not self.psk:
            return True, data  # No PSK configured, skip validation

        if len(data) < 33:  # 32 byte PSK prefix + at least 1 byte CoAP
            return False, None

        received_psk = data[:32]
        coap_data = data[32:]

        # Constant-time comparison to prevent timing attacks
        if len(received_psk) != len(self.psk):
            return False, None

        result = 0
        for a, b in zip(received_psk, self.psk):
            if isinstance(a, int):
                result |= a ^ b
            else:
                result |= ord(a) ^ ord(b)

        if result == 0:
            return True, coap_data
        return False, None

    def start(self):
        """Start the CoAP server."""
        print("=" * 50)
        print("Secure CoAP Server for IoT")
        print("=" * 50)
        print("[INFO] Binding to {}:{}".format(self.host, self.port))
        print("[INFO] Registered resources:")
        for path in self.resources:
            res = self.resources[path]
            methods = []
            if res.get_handler:
                methods.append("GET")
            if res.put_handler:
                methods.append("PUT")
            print("  {} [{}]".format(path, ", ".join(methods)))

        # CoAP typically uses UDP
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        sock.bind((self.host, self.port))

        # Set a timeout so we can check for shutdown
        sock.settimeout(1.0)

        ssl_ctx = self._create_ssl_context()

        if self.psk:
            print("[SECURITY] PSK authentication enabled")
        if ssl_ctx:
            print("[SECURITY] TLS/DTLS context available")

        # Explicitly refuse to bind on insecure port 5683
        if self.port == 5683:
            print("[SECURITY] ERROR: Refusing to start on insecure port 5683!")
            print("[SECURITY] Use port 5684 (CoAPS) with DTLS/PSK authentication.")
            sock.close()
            return

        print("[INFO] Server listening on port {} (secured)".format(self.port))
        print()

        self._running = True

        try:
            while self._running:
                try:
                    data, client_addr = sock.recvfrom(2048)
                except OSError:
                    # Timeout - continue loop to check _running flag
                    continue

                if not data:
                    continue

                # PSK validation layer
                if self.psk:
                    is_valid, coap_data = self._validate_psk(data)
                    if not is_valid:
                        print("[SECURITY] Invalid PSK from {}".format(client_addr))
                        # Send CoAP RST or just drop
                        continue
                    data = coap_data

                try:
                    response_data = self._handle_request(data, client_addr)
                    if response_data:
                        # If PSK mode, we could prepend a response token here
                        sock.sendto(response_data, client_addr)
                except Exception as e:
                    print("[ERROR] Handling request from {}: {}".format(
                        client_addr, e
                    ))
                    # Try to send error response
                    try:
                        request = CoapMessage.parse(data)
                        if request:
                            err_resp = self._build_response(
                                request,
                                RESPONSE_INTERNAL_ERROR,
                                b"Internal error",
                                CONTENT_PLAIN_TEXT
                            )
                            sock.sendto(err_resp.to_bytes(), client_addr)
                    except Exception:
                        pass

        except KeyboardInterrupt:
            print("\n[INFO] Shutting down...")
        finally:
            self._running = False
            sock.close()
            print("[INFO] Server stopped.")

    def stop(self):
        """Signal the server to stop."""
        self._running = False


