def create_custom_server():
    """
    Factory function to create a configured CoAP server.
    Customize PSK, certificates, and additional resources here.
    """

    # Pre-shared key (32 bytes) for lightweight authentication
    # In production, load from secure storage / hardware security module
    PSK_KEY = b'\x01\x02\x03\x04\x05\x06\x07\x08' \
              b'\x09\x0a\x0b\x0c\x0d\x0e\x0f\x10' \
              b'\x11\x12\x13\x14\x15\x16\x17\x18' \
              b'\x19\x1a\x1b\x1c\x1d\x1e\x1f\x20'

    server = SecureCoapServer(
        host="0.0.0.0",
        port=COAP_PORT,       # 5684 - secured CoAP
        psk=PSK_KEY,
        # certfile="device_cert.pem",  # Uncomment if using X.509
        # keyfile="device_key.pem",
    )

    # --- Add custom resources ---

    # Device info resource (read-only)
    def handle_device_info_get(request):
        info = '{{"device": "iot-node-001", "firmware": "1.0.0", "uptime": {}}}'.format(
            time.time()
        )
        return RESPONSE_CONTENT, info.encode("utf-8"), CONTENT_JSON

    server.add_resource("/device/info", get_handler=handle_device_info_get)

    # Humidity sensor (read-only, simulated)
    def handle_humidity_get(request):
        humidity = round(random.uniform(30.0, 70.0), 1)
        payload = '{{"humidity": {}, "unit": "percent"}}'.format(humidity)
        return RESPONSE_CONTENT, payload.encode("utf-8"), CONTENT_JSON

    server.add_resource("/sensors/humidity", get_handler=handle_humidity_get)

    # GPIO control resource (read/write)
    gpio_states = {"gpio0": False, "gpio1": False, "gpio2": False}

    def handle_gpio_get(request):
        parts = []
        for pin, state in gpio_states.items():
            parts.append('"{}": {}'.format(pin, "true" if state else "false"))
        payload = "{" + ", ".join(parts) + "}"
        return RESPONSE_CONTENT, payload.encode("utf-8"), CONTENT_JSON

    def handle_gpio_put(request):
        if not request.payload:
            return RESPONSE_BAD_REQUEST, b"Empty payload", CONTENT_PLAIN_TEXT
        try:
            payload_str = request.payload.decode("utf-8")
            data = DeviceState._parse_simple_json(payload_str)
            for key, value in data.items():
                if key in gpio_states:
                    gpio_states[key] = bool(value)
            # Return updated state
            return handle_gpio_get(request)
        except Exception as e:
            return RESPONSE_BAD_REQUEST, str(e).encode("utf-8"), CONTENT_PLAIN_TEXT

    server.add_resource(
        "/actuators/gpio",
        get_handler=handle_gpio_get,
        put_handler=handle_gpio_put
    )

    return server


